-- Ken's Hardened V2 Fix

local b64_0xllllIl = {}
local char_0xIl1IIl='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
for i_0xlIlIIl=1,#char_0xIl1IIl do b64_0xllllIl[char_0xIl1IIl:sub(i_0xlIlIIl,i_0xlIlIIl)] = i_0xlIlIIl - 1 end

function b64_0xllllIl.dec_0xl11lI1(d_0xl1llII)
    d_0xl1llII = string.gsub(d_0xl1llII, '[^'..char_0xIl1IIl..'=]', '')
    local r_0xI1IIlI = {}
    for i_0xlIlIIl=1, #d_0xl1llII, 4 do
        local c_0xIlIII1 = b64_0xllllIl[d_0xl1llII:sub(i_0xlIlIIl,i_0xlIlIIl)] or 0
        local c_0xII1lI1 = b64_0xllllIl[d_0xl1llII:sub(i_0xlIlIIl+1,i_0xlIlIIl+1)] or 0
        local c_0xIIlIIl, c_0xl1l1l1 = 0, 0
        local has3 = true
        local has4 = true
        local ch3 = d_0xl1llII:sub(i_0xlIlIIl+2,i_0xlIlIIl+2)
        if ch3 == "=" then has3 = false else c_0xIIlIIl = b64_0xllllIl[ch3] or 0 end
        local ch4 = d_0xl1llII:sub(i_0xlIlIIl+3,i_0xlIlIIl+3)
        if ch4 == "=" then has4 = false else c_0xl1l1l1 = b64_0xllllIl[ch4] or 0 end
        local b_0xll1lI1 = c_0xIlIII1 * (2^18) + c_0xII1lI1 * (2^12) + c_0xIIlIIl * (2^6) + c_0xl1l1l1
        local b_0xIIIIll = math.floor(b_0xll1lI1 / (2^16)) % (2^8)
        local b_0xIl1Ill = math.floor(b_0xll1lI1 / (2^8)) % (2^8)
        local b_0xIIl1ll = b_0xll1lI1 % (2^8)
        table.insert(r_0xI1IIlI, string.char(b_0xIIIIll))
        if has3 then table.insert(r_0xI1IIlI, string.char(b_0xIl1Ill)) end
        if has4 then table.insert(r_0xI1IIlI, string.char(b_0xIIl1ll)) end
    end
    return table.concat(r_0xI1IIlI)
end


local function bxor_0xII1l1I(a_0xI1lIIl,b_0x1lllII)
    if bit32 then return bit32.bxor(a_0xI1lIIl,b_0x1lllII) end
    local r_0xIllIlI = 0
    for i_0x1lllll = 0, 7 do
        local x_0xlIlIl1 = a_0xI1lIIl % 2
        local y_0xIIllll = b_0x1lllII % 2
        if x_0xlIlIl1 ~= y_0xIIllll then r_0xIllIlI = r_0xIllIlI + (2^i_0x1lllll) end
        a_0xI1lIIl = math.floor(a_0xI1lIIl / 2)
        b_0x1lllII = math.floor(b_0x1lllII / 2)
    end
    return r_0xIllIlI
end


local function bxor_str_0xIIIll1(s_0xlllIII, k_0xlllIlI)
    local r_0xIIlIll = {}
    for i_0xIIIlll=1, #s_0xlllIII do
        local b_0x11llll = string.byte(s_0xlllIII, i_0xIIIlll)
        local kb_0xllIl11 = string.byte(k_0xlllIlI, (i_0xIIIlll-1) % #k_0xlllIlI + 1)
        r_0xIIlIll[i_0xIIIlll] = string.char(bxor_0xII1l1I(b_0x11llll, kb_0xllIl11))
    end
    return table.concat(r_0xIIlIll)
end


local function getkeys_0xIIl1ll()
    local seed = b64_0xllllIl.dec_0xl11lI1("YXQySkM5Mk8=")
    local k1_enc = b64_0xllllIl.dec_0xl11lI1("KQQBOwpDdBk=")
    local k2_enc = b64_0xllllIl.dec_0xl11lI1("WTBgeC8IXAo=")
    return bxor_str_0xIIIll1(k1_enc, seed), bxor_str_0xIIIll1(k2_enc, seed)
end


local function cff_0xlII1Il(a_0xlllIII)
    local st_0x1Il1ll = 0
    local res_0xlII1II = a_0xlllIII
    while true do
        if st_0x1Il1ll == 0 then
            res_0xlII1II = res_0xlII1II + 1
            st_0x1Il1ll = 1
        elseif st_0x1Il1ll == 1 then
            res_0xlII1II = res_0xlII1II * 2
            st_0x1Il1ll = 2
        elseif st_0x1Il1ll == 2 then
            res_0xlII1II = res_0xlII1II - 3
            st_0x1Il1ll = 3
        else
            break
        end
    end
    return res_0xlII1II
end


local function chain_0x1lIIll(x) return x*2 end
local function chain_0xIIIlII(x) return chain_0x1lIIll(x)+1 end


local d_0xIlI1II = {
  {op=255, val="", is_enc=true},
}
local pc_0x1lI1I1 = 1
local stk_0xllIIIl = {}
stk_0xllIIIl._jmp = nil


local disp_0xI1lllI = {
    [0] = function() end,
    [1] = function(s, v) table.insert(s, v) end,
    [2] = function(s, v) table.insert(s, _G[v]) end,
    [3] = function(s, v) local val=table.remove(s); _G[v]=val end,
    [4] = function(s, _) table.insert(s, {}) end,
    [5] = function(s, _) local val=table.remove(s); local key=table.remove(s); local t=table.remove(s); t[key]=val; table.insert(s, t) end,
    [16] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a+b) end,
    [17] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a-b) end,
    [18] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a*b) end,
    [19] = function(s) local b=tonumber(table.remove(s)) or 0; local a=tonumber(table.remove(s)) or 0; table.insert(s, a/b) end,
    [32] = function(s, n) 
        local args = {}
        for i=1,tonumber(n) do table.insert(args, 1, table.remove(s)) end
        local f = table.remove(s)
        if type(f) == "function" then
            local result = {f(unpack(args))}
            for _,v in ipairs(result) do table.insert(s, v) end
        else
            print("[LBI] Not a function: "..tostring(f))
        end
    end,
    [33] = function(s) return table.remove(s) end,
    [48] = function(s, offset) 
        local cond = table.remove(s)
        if not cond then 
            s._jmp = tonumber(offset)
        end
    end,
    [49] = function(s, offset)
        s._jmp = tonumber(offset)
    end,
    [255] = function(s, v)
        local fn, err = loadstring(v)
        if not fn then
            print("[LBI] Load error: "..tostring(err))
        else
            local ok, res = pcall(fn)
            if not ok then print("[LBI] Run error: "..tostring(res)) end
        end
    end
}



local k1, k2 = getkeys_0xIIl1ll()

local state_0xII11Il = 0
while true do
    if state_0xII11Il == 0 then  -- FETCH
        if pc_0x1lI1I1 > #d_0xIlI1II then break end
        local inst = d_0xIlI1II[pc_0x1lI1I1]
        local opcode = inst.op
        local val = inst.val
        if inst.is_enc then
            local d = b64_0xllllIl.dec_0xl11lI1(val)
            d = bxor_str_0xIIIll1(d, k2)
            val = bxor_str_0xIIIll1(d, k1)
        end
        stk_0xllIIIl._jmp = nil
        pc_0x1lI1I1 = pc_0x1lI1I1 + 1
        cur_op_0x1I1Ill = opcode
        cur_val_0xll11lI = val
        state_0xII11Il = 1

    elseif state_0xII11Il == 1 then  -- EXECUTE
        local handler = disp_0xI1lllI[cur_op_0x1I1Ill]
        if handler then
            handler(stk_0xllIIIl, cur_val_0xll11lI)
        end
        if stk_0xllIIIl._jmp then
            pc_0x1lI1I1 = pc_0x1lI1I1 + stk_0xllIIIl._jmp
        end
        state_0xII11Il = 0
    else
        break
    end
end
